import{_ as a,o as d,c as r,ae as e}from"./chunks/framework.BeVX27ge.js";const u=JSON.parse('{"title":"練習歷史","description":"","frontmatter":{},"headers":[],"relativePath":"history.md","filePath":"history.md"}'),h={name:"history.md"};function l(i,t,o,n,b,s){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="練習歷史" tabindex="-1">練習歷史 <a class="header-anchor" href="#練習歷史" aria-label="Permalink to &quot;練習歷史&quot;">​</a></h1><blockquote><p>回顧所有練習紀錄，透過篩選與分析找出改善方向</p></blockquote><h2 id="概覽" tabindex="-1">概覽 <a class="header-anchor" href="#概覽" aria-label="Permalink to &quot;概覽&quot;">​</a></h2><p>練習歷史頁面提供您所有練習紀錄的完整列表，支援多維度篩選與排序，讓您輕鬆找到特定的練習紀錄並進行回顧或重新挑戰。</p><h2 id="進入方式" tabindex="-1">進入方式 <a class="header-anchor" href="#進入方式" aria-label="Permalink to &quot;進入方式&quot;">​</a></h2><ul><li>儀表板快速篩選中的 <strong>「全部」</strong> 選項</li><li>直接訪問路徑 <code>/practice-history</code></li></ul><hr><h2 id="頁面結構" tabindex="-1">頁面結構 <a class="header-anchor" href="#頁面結構" aria-label="Permalink to &quot;頁面結構&quot;">​</a></h2><p>頁面由上而下分為以下區域：</p><table tabindex="0"><thead><tr><th>區域</th><th>說明</th></tr></thead><tbody><tr><td>頁面標題列</td><td>包含標題「練習紀錄」、篩選按鈕、開始對話按鈕</td></tr><tr><td>篩選標籤列</td><td>顯示目前套用的篩選條件標籤（可快速移除）</td></tr><tr><td>練習紀錄表格</td><td>顯示所有練習紀錄</td></tr><tr><td>分頁控制列</td><td>分頁導航、每頁顯示筆數設定</td></tr></tbody></table><hr><h2 id="篩選功能" tabindex="-1">篩選功能 <a class="header-anchor" href="#篩選功能" aria-label="Permalink to &quot;篩選功能&quot;">​</a></h2><p>點擊 <strong>「篩選條件」</strong> 按鈕開啟篩選面板。可同時套用多個篩選條件。</p><h3 id="日期範圍" tabindex="-1">日期範圍 <a class="header-anchor" href="#日期範圍" aria-label="Permalink to &quot;日期範圍&quot;">​</a></h3><p>提供開始日期與結束日期的日期選擇器，自行設定所需的日期區間。</p><h3 id="客戶屬性篩選" tabindex="-1">客戶屬性篩選 <a class="header-anchor" href="#客戶屬性篩選" aria-label="Permalink to &quot;客戶屬性篩選&quot;">​</a></h3><table tabindex="0"><thead><tr><th>篩選條件</th><th>類型</th><th>選項</th></tr></thead><tbody><tr><td>年齡範圍</td><td>數字範圍</td><td>最小年齡 ~ 最大年齡（18-65）</td></tr><tr><td>性別</td><td>單選</td><td>男 / 女</td></tr><tr><td>姓名</td><td>文字輸入</td><td>依客戶姓名篩選</td></tr><tr><td>收入</td><td>單選</td><td>5M~10M / 10M~15M / 15M~20M / 大於 20M</td></tr><tr><td>婚姻狀況</td><td>單選</td><td>單身 / 已婚</td></tr><tr><td>關係類型</td><td>單選</td><td>親友 / 陌生客</td></tr><tr><td>達成階段範圍</td><td>數字範圍</td><td>最小達成階段 ~ 最大達成階段</td></tr></tbody></table><h3 id="篩選操作" tabindex="-1">篩選操作 <a class="header-anchor" href="#篩選操作" aria-label="Permalink to &quot;篩選操作&quot;">​</a></h3><table tabindex="0"><thead><tr><th>按鈕</th><th>說明</th></tr></thead><tbody><tr><td>套用</td><td>套用目前的篩選條件</td></tr><tr><td>清除</td><td>清除所有篩選條件</td></tr><tr><td>收摺 / 展開</td><td>收合或展開篩選面板</td></tr></tbody></table><h3 id="篩選標籤" tabindex="-1">篩選標籤 <a class="header-anchor" href="#篩選標籤" aria-label="Permalink to &quot;篩選標籤&quot;">​</a></h3><p>套用篩選後，頁面會在表格上方顯示篩選標籤，每個標籤代表一個篩選條件：</p><ul><li>點擊標籤上的 X 可移除該條件</li><li>點擊 <strong>「清除全部」</strong> 可一次移除所有篩選</li></ul><hr><h2 id="練習紀錄表格" tabindex="-1">練習紀錄表格 <a class="header-anchor" href="#練習紀錄表格" aria-label="Permalink to &quot;練習紀錄表格&quot;">​</a></h2><h3 id="表格欄位" tabindex="-1">表格欄位 <a class="header-anchor" href="#表格欄位" aria-label="Permalink to &quot;表格欄位&quot;">​</a></h3><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>日期</td><td>練習進行的日期與時間</td></tr><tr><td>年齡</td><td>客戶角色年齡</td></tr><tr><td>性別</td><td>客戶角色性別</td></tr><tr><td>姓名</td><td>客戶角色姓名</td></tr><tr><td>職業</td><td>客戶角色職業</td></tr><tr><td>收入</td><td>客戶角色收入等級</td></tr><tr><td>婚姻狀況</td><td>單身 / 已婚</td></tr><tr><td>子女數量</td><td>客戶子女數量</td></tr><tr><td>與業務員關係</td><td>親友 / 陌生客</td></tr><tr><td>達成階段</td><td>練習最終達成的銷售階段</td></tr><tr><td>練習時長</td><td>對話時長（分鐘）</td></tr><tr><td>操作</td><td>操作按鈕列</td></tr></tbody></table><h3 id="操作按鈕" tabindex="-1">操作按鈕 <a class="header-anchor" href="#操作按鈕" aria-label="Permalink to &quot;操作按鈕&quot;">​</a></h3><p>每筆紀錄右側提供三個操作按鈕：</p><table tabindex="0"><thead><tr><th>按鈕</th><th>說明</th></tr></thead><tbody><tr><td>查看評量</td><td>前往該次練習的評量報告頁面，檢視詳細評核結果</td></tr><tr><td>重新挑戰</td><td>使用相同客戶角色，開啟全新對話進行練習</td></tr><tr><td>繼續練習</td><td>接續未完成的對話（僅限進行中的練習可用）</td></tr></tbody></table><hr><h2 id="分頁" tabindex="-1">分頁 <a class="header-anchor" href="#分頁" aria-label="Permalink to &quot;分頁&quot;">​</a></h2><p>當紀錄數量超過每頁顯示上限時，頁面底部會出現分頁控制列：</p><table tabindex="0"><thead><tr><th>元素</th><th>說明</th></tr></thead><tbody><tr><td>顯示筆數</td><td>格式：「顯示第 1-20 筆，共 150 筆」</td></tr><tr><td>每頁顯示</td><td>可調整每頁顯示的筆數</td></tr><tr><td>上一頁 / 下一頁</td><td>分頁導航按鈕</td></tr></tbody></table><hr><h2 id="空白狀態" tabindex="-1">空白狀態 <a class="header-anchor" href="#空白狀態" aria-label="Permalink to &quot;空白狀態&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th>顯示訊息</th></tr></thead><tbody><tr><td>完全沒有紀錄</td><td>暫無練習紀錄</td></tr><tr><td>篩選後無結果</td><td>當前條件下暫無練習紀錄，請清除條件或修改條件後重試</td></tr></tbody></table><hr><h2 id="使用建議" tabindex="-1">使用建議 <a class="header-anchor" href="#使用建議" aria-label="Permalink to &quot;使用建議&quot;">​</a></h2><h3 id="找出弱項" tabindex="-1">找出弱項 <a class="header-anchor" href="#找出弱項" aria-label="Permalink to &quot;找出弱項&quot;">​</a></h3><ol><li>按「達成階段」篩選，找出只達成第 1 或第 2 階段的練習</li><li>檢視這些練習的評量報告，找出共同的弱點</li><li>針對弱項進行重點練習</li></ol><h3 id="追蹤進步" tabindex="-1">追蹤進步 <a class="header-anchor" href="#追蹤進步" aria-label="Permalink to &quot;追蹤進步&quot;">​</a></h3><ol><li>使用日期範圍篩選特定時間段</li><li>比較不同時期的達成階段分布</li><li>觀察練習時長的變化趨勢</li></ol><h3 id="專項練習" tabindex="-1">專項練習 <a class="header-anchor" href="#專項練習" aria-label="Permalink to &quot;專項練習&quot;">​</a></h3><ol><li>使用收入、婚姻狀況等篩選條件找出特定類型客戶</li><li>檢視針對該類型客戶的歷史表現</li><li>重新挑戰表現不佳的客戶角色</li></ol><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>回到 <a href="./dashboard.html">儀表板</a> 查看統計概覽</li><li>了解 <a href="./evaluation.html">評量報告</a> 的評核內容</li><li>開始新的 <a href="./practice.html">對話練習</a></li></ul>',47)])])}const q=a(h,[["render",l]]);export{u as __pageData,q as default};
